@function reduce($list, $transformer, $args...)

	@if meta.type-of($transformer) != 'function'
		@error parameter-type.parameter-type('reduce', 'transformer', $transformer, 'function')

	$args: meta.keywords($args)
	$accumulator: map.get($args, 'initial-value')
	$length: list.length($list)
	$index: 1

	@if not map.has-key($args, 'initial-value')

		@if $length == 0
			@error parameter.parameter('Reduction of empty list with no initial value', 'reduce', 'list', 'initial-value')

		$accumulator: list.nth($list, 1)

		@if $length == 1
			@return $accumulator

		$index: 2

	@for $index from $index through $length
		$accumulator: meta.call($transformer, $accumulator, list.nth($list, $index), $index, $list)

	@return $accumulator

@function reduce-right($list, $transformer, $args...)

	@if meta.type-of($transformer) != 'function'
		@error parameter-type.parameter-type('reduce-right', 'transformer', $transformer, 'function')

	$args: meta.keywords($args)
	$accumulator: map.get($args, 'initial-value')
	$length: list.length($list)
	$index: $length

	@if not map.has-key($args, 'initial-value')

		@if $length == 0
			@error parameter.parameter('Reduction of empty list with no initial value', 'reduce-right', 'list', 'initial-value')

		$accumulator: list.nth($list, -1)

		@if $index == 1
			@return $accumulator

		$index: $index - 1

	@for $index from $index through 1
		$accumulator: meta.call($transformer, $accumulator, list.nth($list, $index), $index, $list)

	@return $accumulator

@function filter($list, $predicate, $args...)

	@if meta.type-of($predicate) != 'function'
		@error parameter-type.parameter-type('filter', 'predicate', $predicate, 'function')

	$separator: get-keyword.get-keyword($args, 'separator', auto)

	@if is-separator-invalid.is-separator-invalid($separator)
		@error separator.separator('filter')

	$result: empty.empty($separator, $list: $list)
	$index: 1

	$args: strip-keywords.strip-keywords($args)

	@each $item in $list

		@if meta.call($predicate, $item, $index, $list, $args...)
			$result: list.append($result, $item)

		$index: $index + 1

	@return $result

@function map($list, $transformer, $args...)

	@if meta.type-of($transformer) != 'function'
		@return throw.error(parameter-type.parameter-type('map', 'transformer', $transformer, 'function'))

	$separator: get-keyword.get-keyword($args, 'separator', auto)

	@if is-separator-invalid.is-separator-invalid($separator)
		@return throw.error(separator.separator('map'))

	$bracketed: get-keyword.get-keyword($args, 'bracketed', auto)

	$result: empty.empty($separator, $bracketed, $list)
	$index: 1

	$args: strip-keywords.strip-keywords($args)

	@each $item in $list
		$result: list.append($result, meta.call($transformer, $item, $index, $list, $args...))
		$index: $index + 1

	@return $result

@function modular-scale($multiple, $base-size, $ratio)

  // On init, $modular-scale equals the default value of $base-size or the value passed to the function
  $modular-scale: $base-size

  // If $multiple is a positive integer (up the scale)
  @if $multiple > 0
    @for $i from 1 through $multiple
      $modular-scale: $modular-scale * $ratio

  // If $multiple is a negative integer (down the scale)
  @if $multiple < 0
    @for $i from 1 through ($multiple * -1)
      $modular-scale: $modular-scale / $ratio

  // Return the new or unchanged value of $modular-scale
  @return $modular-scale

@function chunk($list, $size)
  @if not meta.is-number($size)
    @error '$size: `#{$size}` not a number'
  // Length of the given list to split.
  $length: list.length($list)
  // Final result with all created chunks.
  $result: -same-format-($list)
  // Returns only 1 chunk if size is too small.
  @if $size >= $length
    @return list.append($result, $list)
  // Chunks amount to be created from the list.
  $amount: math.ceil(math.div($length, $size))
  @for $i from 0 to $amount
    $chunk: -same-format-($result)
    @for $j from 1 through $size
      $index: $i * $size + $j
      @if $index <= $length
        $item: list.nth($list, $index)
        $chunk: list.append($chunk, $item)
    $result: list.append($result, $chunk)
  @return $result

=single-text-shadow($hoff: false, $voff: false, $blur: false, $spread: false, $color: false)
  // A lot of people think the color comes first. It doesn't.
  @if type-of($hoff) == color
    $temp-color: $hoff
    $hoff: $voff
    $voff: $blur
    $blur: $spread
    $spread: $color
    $color: $temp-color
  // Can't rely on default assignment with multiple supported argument orders.
  $hoff: if($hoff, $hoff, $default-text-shadow-h-offset)
  $voff: if($voff, $voff, $default-text-shadow-v-offset)
  $blur: if($blur, $blur, $default-text-shadow-blur)
  $spread: if($spread, $spread, $default-text-shadow-spread)
  $color: if($color, $color, $default-text-shadow-color)
  // We don't need experimental support for this property.
  @if $color == none or $hoff == none
    +text-shadow(none)
  @else
    +text-shadow(compact($hoff $voff $blur $spread $color))
